using System.Runtime.InteropServices;
using TextAnalysis;

const int WarmupIterations = 500;
const int MeasuredIterations = 5000;
const int Rounds = 5;

// Build test data
var smallAnalyzer = new TextAnalyzer("The quick brown fox jumps over the lazy dog near the river bank");

var rng = new Random(42);
var words = new string[10_000];
for (int i = 0; i < words.Length; i++)
{
    int len = rng.Next(1, 15);
    var chars = new char[len];
    for (int j = 0; j < len; j++)
        chars[j] = (char)('a' + rng.Next(0, 26));
    words[i] = new string(chars);
}
var largeAnalyzer = new TextAnalyzer(string.Join(' ', words));

Console.WriteLine($"Runtime: {RuntimeInformation.FrameworkDescription}");
Console.WriteLine($"Warmup: {WarmupIterations}  Measured: {MeasuredIterations}  Rounds: {Rounds}");
Console.WriteLine();

var benchmarks = new (string Name, Func<object> Action)[]
{
    ("AverageWordLength_Small", () => { var r = smallAnalyzer.AverageWordLength(); return Unsafe.As<double, object>(ref r); }),
    ("AverageWordLength_Large", () => { var r = largeAnalyzer.AverageWordLength(); return Unsafe.As<double, object>(ref r); }),
    ("WordLengthHistogram_Small", () => smallAnalyzer.WordLengthHistogram()),
    ("WordLengthHistogram_Large", () => largeAnalyzer.WordLengthHistogram()),
    ("UniqueWordCount_Small", () => { var r = smallAnalyzer.UniqueWordCount(); return Unsafe.As<int, object>(ref r); }),
    ("UniqueWordCount_Large", () => { var r = largeAnalyzer.UniqueWordCount(); return Unsafe.As<int, object>(ref r); }),
};

Console.WriteLine($"{"Benchmark",-30} {"Mean (ns)",>12} {"StdDev (ns)",>12} {"Min (ns)",>12} {"Median (ns)",>12}");
Console.WriteLine(new string('-', 82));

foreach (var (name, action) in benchmarks)
{
    // Warmup
    for (int i = 0; i < WarmupIterations; i++)
        action();

    var roundMeans = new double[Rounds];

    for (int r = 0; r < Rounds; r++)
    {
        var sw = Stopwatch.StartNew();
        for (int i = 0; i < MeasuredIterations; i++)
            action();
        sw.Stop();
        roundMeans[r] = (double)sw.ElapsedTicks / MeasuredIterations * 1_000_000_000.0 / Stopwatch.Frequency;
    }

    double mean = roundMeans.Average();
    double stddev = Math.Sqrt(roundMeans.Select(x => (x - mean) * (x - mean)).Sum() / roundMeans.Length);
    double min = roundMeans.Min();
    Array.Sort(roundMeans);
    double median = roundMeans[Rounds / 2];

    Console.WriteLine($"{name,-30} {mean,12:F2} {stddev,12:F2} {min,12:F2} {median,12:F2}");
}

