1. using System.Diagnostics;
2. using System.Runtime.InteropServices;
3. using TextAnalysis;
4. 
5. const int WarmupIterations = 500;
6. const int MeasuredIterations = 5000;
7. const int Rounds = 5;
8. 
9. // Build test data
10. var smallAnalyzer = new TextAnalyzer("The quick brown fox jumps over the lazy dog near the river bank");
11. 
12. var rng = new Random(42);
13. var words = new string[10_000];
14. for (int i = 0; i < words.Length; i++)
15. {
16.     int len = rng.Next(1, 15);
17.     var chars = new char[len];
18.     for (int j = 0; j < len; j++)
19.         chars[j] = (char)('a' + rng.Next(0, 26));
20.     words[i] = new string(chars);
21. }
